var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"조금은 아쉬운걸. 우리를 줄곧 탄압하던 작자가 이렇게 매력 넘치는 관객이셨다니.","JPN":"少し残念だわ。私たちをずっと迫害していた者がこんな魅力あふれる観客だったとは。","ENG":"It's a shame, really. Who could have known our oppressor was such a charming audience?","TWN":"真可惜～沒想到一直打壓我們的傢伙，竟然是如此有魅力的觀眾！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"적이라도 손에 넣으려고 하는 대범함, 칼날 앞에서 흐트러지지 않는 의연함…….","JPN":"敵であろうと手に入れようとする大胆さ、敵に直面しても乱れない毅然たる態度……","ENG":"You're so bold that you'd recruit your enemy. And confident enough to retain your composure in front of the blade…","TWN":"就算是敵人也要得到手的氣度，在刀刃面前私毫不動搖的處之泰然……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"정말 마음에 들어. 나도 모르게 죽여 버리고 싶을 만큼.","JPN":"本当に気に入ったわ。思わず殺してしまいたいほど。","ENG":"I really like you. So much so that I might just kill you without even thinking.","TWN":"愛了！愛到想殺死你。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"네 눈에 지금의 나는 어때 보여? 사랑의 열병에 걸린 소녀? 아니면 고깃덩이에 눈독 들이는 들개?","JPN":"君の目に今の私はどう見える？　恋煩いに悩む少女？　それとも餌に目を付けている野良犬？","ENG":"So what do I look like to you right now? A girl swooning over her feverish crush? Or a hungry feral dog eying a delicious hunk of meat?","TWN":"現在在你眼裡的我是什麼樣子？是為愛癲狂的少女？還是眼巴巴看著肉塊的野狗。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"어떻게 보이든 상관없어. 너의 마지막 절규와 합주하고 싶은 심정만큼은 진심이거든.","JPN":"どう見られえても構わない。君の最期の絶叫と合奏したい気持ちだけは本気なの。","ENG":"It doesn't matter. Either way, I'm dead serious about wanting to play my last piece with you.","TWN":"哪個都無所謂，至少我想和你最後的哀號聲合奏是認真的！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"하지만 너 같은 거물께서 일개 연주자인 나 따위에게 순순히 목숨을 내어 줄 리 없지.","JPN":"しかし君ような大物が一介の奏者である私なんかに大人しく命を預けるはずがない。","ENG":"But a big shot like you probably wouldn't give your life to a mere player like me.","TWN":"不過像你這種厲害的角色，怎麼可能乖乖地把性命，交給像我這種小小演奏家呢？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"……그래서 이런 종이 쪼가리를 선물로 준비한 거잖아?","JPN":"……だからこんな紙切れをプレゼントとして用意してきたわけでしょ？","ENG":"…That must be why you've prepared this piece of paper as a gift, huh?","TWN":"……所以才準備這種廢紙當作禮物吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_UI_CONTRACT_PAPER"},{"id":"L19_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"마지막까지 함께라. 확실히 네게도 장송곡을 연주해 줄 바이올리니스트가 한 명 정도는 있어야겠지.","JPN":"最後まで一緒か。確かに君にも葬送曲を演奏してくれるバイオリニストが一人ぐらい居たほうがよさそうね。","ENG":"Together till the very end, huh. I suppose you could use a violinist to play your requiem one day.","TWN":"一起走到最後吧！畢竟你也需要一位，能夠替你演奏送葬曲的小提琴家嘛～"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"좋아. 어떤 비참한 결말을 맞이하더라도, 나만은 너의 최후를 아름답게 장식해 줄게.","JPN":"いいわ。どんな悲惨な結末を迎えるとしても、私だけは君の最期を美しく飾ってあげる。","ENG":"Very well. No matter how tragic your end may be, I'll be there to serenade your passing.","TWN":"好！不管結局有多悲慘，我答應你，一定會讓你走得漂亮！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"비통한 단말마든 평온한 탄식이든, 네가 남기는 음색이 내게 번뜩이는 영감을 내려 줄 테니까.","JPN":"悲痛な断末魔であれ平穏な嘆きであれ、君が残す音色が私にきらめくインスピレーションを与えてくれるでしょう。","ENG":"Whether it's a bitter scream or a relaxed sigh, your final melody will surely inspire me.","TWN":"因為無論是好死或是慘死，你留下的聲音，都會成為我美妙的靈感。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"후훗, 고맙다고? 감사 인사는 내가 하고 싶은 심정인걸?","JPN":"フフッ、ありがとうって？感謝の言葉はこちらからしないと。","ENG":"Haha, you appreciate it? If anything, I should be the one thanking you.","TWN":"呵呵，感謝我嗎？我才想謝謝你呢～"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"항상 내 연주에서 눈을 떼지 마. 나는 악보 없는 즉흥곡을 사랑하니까.","JPN":"常に私の演奏から目を離さないで。私は楽譜のない即興曲を好んでいるから。","ENG":"Never let down your guard when I'm playing. I prefer to go impromptu rather than sticking to the score.","TWN":"千萬不要把目光從我的演奏中挪開，因為我喜歡走不看樂譜的FreeStyle路線。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};